import React from "react";
import axios from "axios";

class Volu extends React.Component{
    state = {
        Voluntiring_id:"",
        Category :"",
        Description:"",
        address:"",
        company_id:""

    };


    handleChange(e){
        this.setState({
         [e.target.name]:e.target.value,
        })
    } ;


