//     console.log("Error",err);
//   });
//    }


     handleSubmit(e){
    axios.post("https://localhost:5000/Volunteering",{ 
    Voluntiring_id:this.state.Voluntiring_id,
    Category :this.state.Category,
    Description:this.state.Description,
    address:this.state.address,
    company_id:this.state.company_id,
   }).then((res)  => {
    console.log(res.data) // array of object
  }).catch((err) => { 
    console.log(err);
  });
   }


    render(){
        return(
            <div>
                <h2>Voluntiring form</h2>
                <form onSubmit={this.handleSubmit={}}>
                <lable>Voluntiring ID</lable>
                    <input value= {this.state.Voluntiring_id} onChange={this.handleChange.bind(this)}></input>
                    <br/>
                    <br/>
                    <lable>Category</lable>
                    <input type="text" value= {this.state.Category} onChange={this.handleChange.bind(this)}></input>
                    <br/>
                    <br/>
                    <lable>Description</lable>
                    <input type="text" value= {this.state.Description} onChange={this.handleChange.bind(this)}></input>
                    <br/>
                    <br/>
                    <lable>address</lable>
                    <input type="text" value= {this.state.address } onChange={this.handleChange.bind(this)}></input>
                    <br/>
                    <br/>
                    <lable>company_id</lable>
                    <input value= {this.state.company_id} onChange={this.handleChange.bind(this)}></input>
                    <br/>
                    <br/>


                    <button> Add voluntering work</button>
                </form>
            </div>
        )
    }


}

export default Volu
